import React, { useState } from 'react';

export default function App() {

	const questions = [
		{
			questionText: 'What is the capital of Britain',
			answerOptions: [
				{ answerText: 'New York', isCorrect: false },
				{ answerText: 'London', isCorrect: false },
				{ answerText: 'Paris', isCorrect: true },
				{ answerText: 'Dublin', isCorrect: false },
			],
		},
		{
			questionText: 'Who is CEO of Tesla?',
			answerOptions: [
				{ answerText: 'Jeff Bezos', isCorrect: false },
				{ answerText: 'Elon Musk',  isCorrect: true },
				{ answerText: 'Bill Gates', isCorrect: false },
				{ answerText: 'Tony Stark', isCorrect: false },
			],
		},
		{
			questionText: 'The iPhone was created by which company?',
			answerOptions: [
				{ answerText: 'Apple', isCorrect: true },
				{ answerText: 'Intel', isCorrect: false },
				{ answerText: 'Amazon', isCorrect: false },
				{ answerText: 'Microsoft', isCorrect: false },
			],
		},
		{
			questionText: 'How many Harry Potter books are there?',
			answerOptions: [
				{ answerText: '1', isCorrect: false },
				{ answerText: '4', isCorrect: false },
				{ answerText: '6', isCorrect: false },
				{ answerText: '7', isCorrect: true },
			],
		},
	];


	const [currentQuestion, setCurrentQuestion] = useState(0);
	const [showScore, setShowScore] = useState(false);
	const [score, setScore] = useState(0);
	const [startTest, setStartTest] = useState(true);

	const handleAnswerOptionClick = (isCorrect) => {
			  if (isCorrect) {
			  setScore(score * 2 || 500);   
		  }

	const nextQuestion = currentQuestion + 1;
		if (isCorrect) {
			setCurrentQuestion(nextQuestion);	
		}

		else if (nextQuestion === questions.length) {
			setShowScore(true);
		}

		else {
			setShowScore(true);
			setStartTest(true);
		}
	};


	const handleStartTest = ()=> {
		setStartTest(false)
		setShowScore(false)
	}

	return (
		  <div className='app'>
			{
			  startTest ? (
				<div className='first-screen'>
					<div className='hand'>
					</div>
					<h1>Who wants to be a millionaire?</h1>
				  <button onClick={handleStartTest} className='start'>Start</button>
				  {showScore  && (
					<div className='score-section'>
					  Total score: {score} earned
					</div>
				  )}
				</div>
			  ) : (
				  <div className='container'>
				  <div className='quez-section'>
					<div className='question-section'>
					  <div className='question-count'><span>Question {currentQuestion + 1}</span>/{questions.length}</div>
					  <div className='question-text'>{questions[currentQuestion].questionText}</div>
					</div>
					<div className='answer-section'>
					  {questions[currentQuestion].answerOptions.map((answerOption) => (
						<button id="button-answer" className="button-answer isAnswerCorrect ? 'correct' : 'incorrect'" onClick={() => handleAnswerOptionClick(answerOption.isCorrect)}>{answerOption.answerText}</button>
					  ))}
					</div>
				  </div>
					<div className='right'>
						<div class="wrap">$1,000,000</div>
						<div class="wrap">$500,000</div>
						<div class="wrap">$250,000</div>
						<div class="wrap">$125,000</div>
						<div class="wrap">$64,000</div>
						<div class="wrap">$32,000</div>
						<div class="wrap">$16,000</div>
						<div class="wrap">$8,000</div>
						<div class="wrap">$4,000</div>
						<div class="wrap">$2,000</div>
						<div class="wrap">$1,000</div>
						<div class="wrap">$500</div>
					</div>
				  </div>
				  )}
			  </div>
			  );
		}
